var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"으음……","JPN":"ううむ……","ENG":"Mm...","TWN":"唔……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"너무 갑자기 움직이지 마세요, 사나에.","JPN":"いきなり動かないでください、早苗。","ENG":"Do not move so hastily, Sanae.","TWN":"動作不要太大，早苗。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"상처의 출혈이 멎었군요.","JPN":"出血が止まりましたね。","ENG":"My bleeding has stopped.","TWN":"傷口的出血止住了。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"또 사람들을 치료해주고 계신 겁니까?","JPN":"また人々の手当をしていらっしゃるのですか？","ENG":"Were you treating people again?","TWN":"您又替人治療嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"당주님께서도 많이 지치셨을 텐데요.","JPN":"ご当主様もそうとうお疲れのはずですが。","ENG":"But you must be exhausted.","TWN":"堂主應該也很疲憊吧？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 괜찮아요. 제가 무사한 건 모두의 도움이 있었기 때문인 걸요.","JPN":"私は平気です。私が無事なのは皆さんの助けがあってこそですから。","ENG":"I am all right. I am safe due to everyone's help.","TWN":"我沒事，我之所以能夠平安無事，也都是因為有大家幫忙。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"치후유님은……?","JPN":"千冬様は……？","ENG":"And Miss Chifuyu...?","TWN":"千冬呢……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"역귀들과 싸우고 있어요.","JPN":"疫鬼たちと戦っています。","ENG":"She is fighting the Plagued Ghosts.","TWN":"正在對付疫鬼。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"피에 잠시나마 저항하는 것 같아 보였지만…… 이미 한계이겠죠.","JPN":"血に少しは抵抗しているように見えましたけど……もう限界でしょう。","ENG":"I thought she was resisting the blood, but... I think she has reached her limit.","TWN":"看起來她暫時能抵抗血液的侵蝕……不過應該已經差不多到達極限。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"나나하라 당주.","JPN":"七原当主。","ENG":"Lady Nanahara.","TWN":"七原堂主。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……나오님.","JPN":"……ナオ様。","ENG":"...Miss Nao.","TWN":"……奈緒大人。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"죄송해요. 저는 결국…… 아무것도 바꾸지 못했습니다.","JPN":"すみません。私は結局……何も変えられませんでした。","ENG":"Forgive me. I... could not change anything.","TWN":"對不起，結果……我也什麼都沒能改變。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주가 되어서, 포기라도 할 셈이냐?","JPN":"当主なのに、諦めるつもりか？","ENG":"Are you going to give up that easily?","TWN":"你當堂主的目的是想放棄嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저들은 미래를 알고 있지만…… 저는 아무것도 들을 수 없습니다.","JPN":"彼らは未来を知っていますが……私は何も聞くことができません。","ENG":"They know what the future holds. However... I cannot hear anything.","TWN":"他們知道未來……但我卻什麼都聽不到。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"지금까지 전부 저들의 계획에 당해왔는데, 이제 와서 뭘 할 수 있나요?","JPN":"今まで全部彼らの計画どおりにやられてきたのに、今さら何ができるのですか？","ENG":"We have been straggled along into their plan. So what is there that I can do?","TWN":"到現在為止，全都被他們的計畫牽著鼻子走，我現在還能做什麼？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래, 우리가 놓친 기회들을 만회하기엔 너무 늦었지.","JPN":"わしらが逃した機会を挽回するには遅すぎるのう。","ENG":"Yes, it is too late to make up for our lost opportunities.","TWN":"沒錯，想挽回我們錯失的機會已經來不及，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하지만 최악의 상황을 막을 방법은 아직 남아있다.","JPN":"しかし、最悪の状況を止められる方法はまだ残っておる。","ENG":"But there is still a way to stop the worst.","TWN":"但是還有辦法阻止最壞的情況發生。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 시도마저도 저들의 계획이라면…… 그땐 어쩌면 좋죠?","JPN":"その方法までも彼らの計画のうちだったら……その時はどうしたらよいのですか？","ENG":"And if that is also a part of their plan...? What do we do then?","TWN":"如果連這個辦法也在他們的計畫之內……到時候該怎麼辦呢？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"여기서 아무것도 하지 않으면, 역신이 네 동생의 몸에서 깨어날 뿐이다.","JPN":"今何もしなければ、疫病神がお主の妹の中で目覚めるだけじゃ。","ENG":"By doing nothing here, the Plague God will awaken inside your sister's body.","TWN":"要是我們在這裡什麼都不做，結果就是瘟神會在你妹妹的體內甦醒。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그것만은 막아야 해.","JPN":"それだけは止めなければ。","ENG":"We must stop that at all costs.","TWN":"最起碼我們必須阻止這件事。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 말씀해주십시오.","JPN":"でしたら、お話しください。","ENG":"Then please, tell me.","TWN":"那請您告訴我，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 무엇을 하면 좋은 것인지.","JPN":"私が何をすればいいかを。","ENG":"What can I do?","TWN":"我該做什麼。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이 몸이 네 동생에게 닿는 길을 열겠다.","JPN":"わしがお主の妹までの道を開けよう。","ENG":"I'll open the way for you to reach your sister.","TWN":"我會打開一條通向你妹妹的路。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러니 넌 그 천총운검으로 네 동생을 베어라.","JPN":"じゃから、お主はその天叢雲剣で妹を斬れ。","ENG":"Once the path is clear, slash her with the Sword of Kusanagi.","TWN":"接著你就用那把天叢雲劍殺掉你妹妹。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"놈들의 목적은 처음부터 네 동생이었어.","JPN":"奴らの目的は最初からお主の妹だった。","ENG":"They were after your sister from the start.","TWN":"他們的目標從一開始就是你妹妹。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신의 힘을 견뎌내는 그 아이를 그릇으로 삼아 잠든 명부신을 이승에 불러들일 셈이다.","JPN":"疫病神の力に耐えられるあの子を器にし、眠っている冥府の神をこの世に呼ぶつもりじゃ。","ENG":"They are going to summon the slumbering Nether God to this world using her as a vessel.","TWN":"他們打算把你妹妹當作器皿，將沉睡的冥府神召喚到現世。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 계획을 막으려면, 명부신이 오로치의 목을 베어 봉인했듯이 그릇을 베어야만 한다.","JPN":"その計画を止めるには、冥府の神がオロチの首を切って封印したように器を斬らなければならぬ。","ENG":"To stop their plan, you must cut the vessel just as Nether God had cut off Orochi's heads and sealed it.","TWN":"要想阻止這個計畫，就必須像當年冥府神斬下大蛇的頭將其封印一樣，要斬殺那個器皿。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"아직 역신에게 몸을 완전히 빼앗기지 않은 지금이 유일한 기회야.","JPN":"まだ疫病神に体をすべて乗っ取られていない今が唯一の機会じゃ。","ENG":"This is our only window before the Plague God completely takes over her body.","TWN":"趁她現在還沒完全被瘟神奪走身體，這是唯一的機會。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"承知しました。","ENG":"As you wish.","TWN":"好的。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"희생 없이 이뤄내는 기적 같은 건…… 쫓아봐야 허망해질 뿐인 신기루겠죠.","JPN":"犠牲なくして叶う奇跡など……追っても届くことのない蜃気楼のようなものでしょう。","ENG":"A miracle without any sacrifice is... like chasing after a mirage.","TWN":"沒有犧牲就得到的奇蹟……不過就是海市蜃樓而已。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나오님.","JPN":"ナオ様。","ENG":"Miss Nao.","TWN":"奈緒大人。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다음 세대가 살아남는다면, 그때엔 세번째 신기를 완성할 수 있을까요?","JPN":"次の世代が生き残れば、その時には三つ目の神器は完成されるのでしょうか？","ENG":"If there is a next generation, will they be able to complete the third Sacred Treasure?","TWN":"若是有下一個世代存活下來，到時候能完成第三個神器嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……신기의 완성은 신도 예견하지 못했다.","JPN":"……神器の完成は神も予言できなかった。","ENG":"...Completing the Sacred Treasure is something even god cannot foresee.","TWN":"……連神都無法預知神器是否能完成。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"결계가 무너지고 저승이 열린 세상은 지금보다 더 끔찍해지겠지만……","JPN":"結界が崩れ、冥府が開いた世界は今よりもさらに悲惨になるじゃろうが……","ENG":"The world will be worse if the barrier collapses and the gateway to the Afterlife opens...","TWN":"結界瓦解後，地獄被開啟的世界或許會變得比現在更可怕……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그래도 살아남은 무녀가 있다면, 언젠가는 기회가 있겠지.","JPN":"それでも生き残った巫女がいるなら、いつかは機会があるはずじゃ。","ENG":"But our time will come one day, if there still is a living priestess.","TWN":"但只要有巫女存活下來，就一定會有機會。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그럼, 마지막으로 부탁드리겠습니다.","JPN":"それでは、最後にお願いします。","ENG":"Then, if I may make this one last request...","TWN":"那我最後要拜託您一件事。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주의 호위로서…… 한날한시에 태어난 운명의 단짝으로서……","JPN":"当主の護衛として……同じ日に生まれた運命の相棒として……","ENG":"As my bodyguard... and my beloved twin fated to be born on the same day...","TWN":"她作為堂主的護衛……身為同年同月同日生的命運夥伴……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그 아이의 바람, 사명을 지켜낼 수 있도록……","JPN":"あの子の願い、使命を守れるように……","ENG":"For her to fulfill her duties and wishes...","TWN":"我想守護她的希望和使命……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"부디 저를 도와주세요.","JPN":"どうか私を手伝ってください。","ENG":"Please help me, one last time.","TWN":"請您幫助我。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크으으……</color>","JPN":"<color=#ff3636>グルル……</color>","ENG":"<color=#ff3636>Khhhkkk...</color>","TWN":"<color=#ff3636>呃呃呃……</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유, 내 목소리가 들리니?","JPN":"千冬、私の声が聞こえる？","ENG":"Chifuyu, can you hear me?","TWN":"千冬，你聽得到我的聲音嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이것 말고는 다른 방법을 찾지 못해서…… 미안해.","JPN":"こんな方法しか見つからなくて……ごめんね。","ENG":"I am sorry... But I could not find another way.","TWN":"對不起……我想不到其他更好的方法。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"<color=#ff3636>……크아아아아!!!!</color>","JPN":"<color=#ff3636>……クアアアア！！！！</color>","ENG":"<color=#ff3636>Gwaaaah!!!</color>","TWN":"<color=#ff3636>……呃啊啊啊啊！！！</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L15_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"온다!","JPN":"来るぞ！","ENG":"She's coming this way!","TWN":"來了！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};